// src/pages/AllMaterials.jsx
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaFilePdf, FaFileAlt, 
  FaArrowLeft, FaSpinner, FaUser, FaSearch,
  FaFilter, FaFileWord, FaFilePowerpoint, FaFileImage,
  FaFileArchive
} from 'react-icons/fa';

const AllMaterials = () => {
  const navigate = useNavigate();
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  
  const materialTypes = [
    { id: 'all', name: 'All Materials' },
    { id: 'notes', name: 'Notes' },
    { id: 'syllabus', name: 'Syllabus' },
    { id: 'pyq', name: 'PYQs' },
    { id: 'important', name: 'Imp Questions' },
    { id: 'lab', name: 'Lab Manuals' },
    { id: 'assignment', name: 'Assignments' }
  ];

  useEffect(() => {
    fetchAllMaterials();
  }, []);

  const fetchAllMaterials = async () => {
    try {
      setLoading(true);
      const response = await fetch('http://localhost:5000/api/materials');
      const data = await response.json();
      
      if (data.success) {
        setMaterials(data.materials);
      } else {
        console.error('Failed to fetch materials');
      }
    } catch (error) {
      console.error('Error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = async (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    try {
      const token = localStorage.getItem('study_portal_token');
      const response = await fetch(`http://localhost:5000/api/notes/${material.id}/download`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      if (!response.ok) throw new Error('Download failed');
      
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = material.file_name || `${material.title}.pdf`;
      link.click();
      window.URL.revokeObjectURL(url);
      
    } catch (error) {
      console.error('Download error:', error);
      alert('Download failed');
    } finally {
      setDownloading(prev => ({ ...prev, [material.id]: false }));
    }
  };

  const filteredMaterials = materials.filter(m => {
    const matchesType = selectedType === 'all' || m.type === selectedType;
    const matchesSearch = searchQuery === '' ||
      m.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (m.course && m.course.toLowerCase().includes(searchQuery.toLowerCase()));
    return matchesType && matchesSearch;
  });

  const getFileIcon = (type) => {
    if (type?.includes('pdf')) return <FaFilePdf color="#ef4444" />;
    if (type?.includes('doc')) return <FaFileWord color="#2563eb" />;
    if (type?.includes('ppt')) return <FaFilePowerpoint color="#f97316" />;
    return <FaFileAlt color="#6b7280" />;
  };

  const styles = {
    container: {
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '20px'
    },
    inner: {
      maxWidth: '1200px',
      margin: '0 auto'
    },
    header: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      marginBottom: '20px'
    },
    backBtn: {
      padding: '10px 20px',
      background: 'white',
      color: '#4f46e5',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      gap: '8px'
    },
    title: {
      fontSize: '32px',
      fontWeight: 'bold',
      color: 'white',
      marginBottom: '20px'
    },
    searchInput: {
      width: '100%',
      padding: '15px 20px',
      border: '2px solid #e5e7eb',
      borderRadius: '10px',
      fontSize: '16px',
      marginBottom: '20px'
    },
    filterContainer: {
      background: 'white',
      padding: '20px',
      borderRadius: '12px',
      marginBottom: '20px'
    },
    filterButtons: {
      display: 'flex',
      flexWrap: 'wrap',
      gap: '10px',
      marginTop: '10px'
    },
    filterBtn: {
      padding: '8px 16px',
      border: '2px solid #e5e7eb',
      borderRadius: '6px',
      background: 'white',
      cursor: 'pointer'
    },
    activeFilter: {
      background: '#4f46e5',
      color: 'white',
      borderColor: '#4f46e5'
    },
    materialsGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
      gap: '20px'
    },
    card: {
      background: 'white',
      borderRadius: '12px',
      padding: '20px',
      boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
    },
    cardHeader: {
      display: 'flex',
      justifyContent: 'space-between',
      marginBottom: '10px'
    },
    typeBadge: {
      padding: '4px 12px',
      borderRadius: '20px',
      fontSize: '12px',
      fontWeight: 'bold'
    },
    cardTitle: {
      fontSize: '18px',
      fontWeight: '600',
      color: '#1f2937',
      marginBottom: '10px'
    },
    cardMeta: {
      color: '#6b7280',
      fontSize: '14px',
      marginBottom: '5px'
    },
    downloadBtn: {
      width: '100%',
      padding: '10px',
      background: '#10b981',
      color: 'white',
      border: 'none',
      borderRadius: '6px',
      marginTop: '15px',
      cursor: 'pointer'
    }
  };

  const getTypeStyle = (type) => {
    const colors = {
      notes: { bg: '#dbeafe', color: '#1d4ed8' },
      syllabus: { bg: '#dcfce7', color: '#15803d' },
      pyq: { bg: '#fef3c7', color: '#d97706' },
      important: { bg: '#f3e8ff', color: '#7c3aed' }
    };
    return colors[type] || { bg: '#f1f5f9', color: '#64748b' };
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <div style={{ textAlign: 'center', padding: '100px', color: 'white' }}>
          <FaSpinner style={{ animation: 'spin 1s linear infinite', fontSize: '40px' }} />
          <h3>Loading materials...</h3>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.inner}>
        <div style={styles.header}>
          <button onClick={() => navigate(-1)} style={styles.backBtn}>
            <FaArrowLeft /> Back
          </button>
        </div>
        
        <h1 style={styles.title}>📚 All Study Materials</h1>
        
        <input
          type="text"
          placeholder="Search materials..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          style={styles.searchInput}
        />
        
        <div style={styles.filterContainer}>
          <h3>Filter by Type</h3>
          <div style={styles.filterButtons}>
            {materialTypes.map(type => (
              <button
                key={type.id}
                style={{
                  ...styles.filterBtn,
                  ...(selectedType === type.id ? styles.activeFilter : {})
                }}
                onClick={() => setSelectedType(type.id)}
              >
                {type.name}
              </button>
            ))}
          </div>
        </div>
        
        {filteredMaterials.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px', background: 'white', borderRadius: '12px' }}>
            <div style={{ fontSize: '60px', marginBottom: '20px' }}>📭</div>
            <h3>No materials found</h3>
            <p>Try adjusting your search or filters</p>
          </div>
        ) : (
          <div style={styles.materialsGrid}>
            {filteredMaterials.map(material => {
              const typeStyle = getTypeStyle(material.type);
              return (
                <div key={material.id} style={styles.card}>
                  <div style={styles.cardHeader}>
                    <span style={{ ...styles.typeBadge, background: typeStyle.bg, color: typeStyle.color }}>
                      {material.type?.toUpperCase()}
                    </span>
                    <span style={{ color: '#6b7280', fontSize: '12px' }}>
                      <FaUser /> {material.user_name || 'Unknown'}
                    </span>
                  </div>
                  
                  <h4 style={styles.cardTitle}>{material.title}</h4>
                  
                  <p style={styles.cardMeta}>
                    <strong>Course:</strong> {material.course || 'All Courses'}
                  </p>
                  
                  <p style={styles.cardMeta}>
                    <strong>Uploaded:</strong> {new Date(material.uploaded_at).toLocaleDateString()}
                  </p>
                  
                  <div style={{ display: 'flex', gap: '10px', marginBottom: '10px' }}>
                    <span style={{ fontSize: '12px', color: '#6b7280' }}>
                      👁️ {material.views || 0}
                    </span>
                    <span style={{ fontSize: '12px', color: '#6b7280' }}>
                      ⬇️ {material.downloads || 0}
                    </span>
                    {getFileIcon(material.file_type)}
                  </div>
                  
                  <button
                    onClick={() => handleDownload(material)}
                    disabled={downloading[material.id]}
                    style={{
                      ...styles.downloadBtn,
                      opacity: downloading[material.id] ? 0.7 : 1
                    }}
                  >
                    {downloading[material.id] ? 'Downloading...' : 'Download'}
                  </button>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default AllMaterials;
